INSERT INTO `mdl_assign` (`id`, `course`, `name`, `intro`, `introformat`, `alwaysshowdescription`, `nosubmissions`, `submissiondrafts`, `sendnotifications`, `sendlatenotifications`, `duedate`, `allowsubmissionsfromdate`, `grade`, `timemodified`, `requiresubmissionstatement`, `completionsubmit`, `cutoffdate`, `gradingduedate`, `teamsubmission`, `requireallteammemberssubmit`, `teamsubmissiongroupingid`, `blindmarking`, `hidegrader`, `revealidentities`, `attemptreopenmethod`, `maxattempts`, `markingworkflow`, `markingallocation`, `markinganonymous`, `sendstudentnotifications`, `preventsubmissionnotingroup`, `activity`, `activityformat`, `timelimit`, `submissionattachments`) VALUES
(1, 2, 'Bài tập nộp code', '<p>Viết các chương trình bằng ngôn ngữ Python</p>\r\n<p>1/ Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 1, 0, 0, 0, 0, 1774803600, 1774717200, 100, 1779266012, 0, 1, 0, 1775926800, 0, 0, 0, 0, 0, 0, 'none', -1, 0, 0, 0, 1, 0, '', 1, 0, 0),
(2, 2, 'Thống kế và phân tích dữ liệu từ bộ dữ liệu Iris', '<p data-pm-slice=\"0 0 []\">1/ Viết chương trình Python sử dụng thư viện pandas và matplotlib để đọc bộ dữ liệu Iris, sau đó:</p>\r\n<p>- Hiển thị 5 dòng đầu tiên của dữ liệu.</p>\r\n<p>- Vẽ biểu đồ scatter giữa sepal_length và petal_length, phân biệt màu theo từng loài hoa (species).</p>\r\n<p>2/ Viết chương trình Python dùng thư viện scikit-learn để:</p>\r\n<p>- Chia bộ dữ liệu Iris thành tập huấn luyện và tập kiểm tra.</p>\r\n<p>- Huấn luyện mô hình KNeighborsClassifier.</p>', 1, 1, 0, 0, 0, 0, 1778950800, 1778346000, 100, 1778402053, 0, 1, 0, 1779555600, 0, 0, 0, 0, 0, 0, 'none', -1, 0, 0, 0, 1, 0, '', 1, 0, 0),
(3, 3, 'Viết chương trình đơn giản', '<p>1/  Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/ Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 1, 0, 0, 0, 0, 1811350800, 1779210000, 100, 1780810811, 0, 1, 0, 1811955600, 0, 0, 0, 0, 0, 0, 'none', -1, 0, 0, 0, 1, 0, '', 1, 0, 0),
(4, 3, 'Viết chương trình áp dụng hướng đối tượng', '<p>Một đơn vị sản xuất gồm có các cán bộ là công nhân, kỹ sư, nhân viên. Mỗi cán bộ cần quản lý các dữ liệu: Họ tên, tuổi, giới tính(nam, nữ, khác), địa chỉ.</p>\r\n<ul>\r\n<li>Cấp công nhân sẽ có thêm các thuộc tính riêng: Bậc (1 đến 10).</li>\r\n<li>Cấp kỹ sư có thuộc tính riêng: Nghành đào tạo.</li>\r\n<li>Các nhân viên có thuộc tính riêng: Công việc.</li>\r\n</ul>\r\n<p>Yêu cầu 1: Xây dựng các lớp <em>CongNhan</em>, <em>KySu</em>, <em>NhanVien</em> kế thừa từ lớp <em>CanBo</em>.</p>\r\n<p>Yêu cầu 2: Xây dựng lớp <em>QLCB</em>(quản lý cán bộ) cài đặt các phương thức thực hiện các chức năng sau:</p>\r\n<ul>\r\n<li>Nhập thông tin cho 1 cán bộ để thêm vào danh sách.</li>\r\n<li>Hiển thị danh sách họ tên các cán bộ. </li>\r\n</ul>', 1, 1, 0, 0, 0, 0, 1811350800, 1779210000, 100, 1782459687, 0, 1, 0, 1811955600, 0, 0, 0, 0, 0, 0, 'none', -1, 0, 0, 0, 1, 0, '', 1, 0, 0),
(5, 3, 'Viết chương trình áp dụng hướng đối tượng 2', '<p>Sinh viên đọc các file bên dưới:</p>\r\n<ul>\r\n<li>Thực hiện theo yêu cầu: file De_bai.docx</li>\r\n<li>Tiêu chi chấm điểm: Tieu_chi_cham_diem.docx</li>\r\n</ul>', 1, 1, 0, 0, 0, 0, 1781197200, 1780592400, 100, 1780635656, 0, 1, 0, 1781802000, 0, 0, 0, 0, 0, 0, 'none', -1, 0, 0, 0, 1, 0, '<p>Nộp đầy đủ các file theo yêu cầu</p>', 1, 0, 0),
(6, 4, 'Tương tác cơ sở dữ liệu', '<p style=\"margin: 0cm; margin-bottom: .0001pt; line-height: 150%;\"><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\">Cho cơ sở dữ liệu <strong>todo_db</strong> </span><span lang=\"EN-US\" style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin; mso-ansi-language: EN-US;\">với</span><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\"> bảng <strong>tasks</strong> gồm các trường:</span></p>\r\n<p style=\"text-indent: -18.0pt; line-height: 150%; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt; margin: 0cm 0cm .0001pt 36.0pt;\"><!-- [if !supportLists]--><span style=\"font-size: 10.0pt; mso-bidi-font-size: 12.0pt; line-height: 150%; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;\"><span style=\"mso-list: Ignore;\">·<span style=\"font: 7.0pt \'Times New Roman\';\">        </span></span></span><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\">id (INT, khóa chính, tự tăng)</span></p>\r\n<p style=\"text-indent: -18.0pt; line-height: 150%; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt; margin: 0cm 0cm .0001pt 36.0pt;\"><!-- [if !supportLists]--><span style=\"font-size: 10.0pt; mso-bidi-font-size: 12.0pt; line-height: 150%; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;\"><span style=\"mso-list: Ignore;\">·<span style=\"font: 7.0pt \'Times New Roman\';\">        </span></span></span><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\">task_name (</span><span lang=\"EN-US\" style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin; mso-ansi-language: EN-US;\">N</span><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\">VARCHAR)</span></p>\r\n<p style=\"text-indent: -18.0pt; line-height: 150%; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt; margin: 0cm 0cm .0001pt 36.0pt;\"><!-- [if !supportLists]--><span style=\"font-size: 10.0pt; mso-bidi-font-size: 12.0pt; line-height: 150%; font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;\"><span style=\"mso-list: Ignore;\">·<span style=\"font: 7.0pt \'Times New Roman\';\">        </span></span></span><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: major-latin;\">created_at (TIMESTAMP)</span></p>\r\n<p style=\"margin: 0cm; margin-bottom: .0001pt; line-height: 150%;\"><span style=\"mso-ascii-font-family: \'Times New Roman\'; mso-ascii-theme-font: major-latin; mso-hansi-font-family: \'Times New Roman\'; mso-hansi-theme-font: major-