(1823, 2, 1778728804, NULL, 'additionalhtmlfooter', '<script>\r\n// Kiểm tra xem đã có token trong localStorage chưa để tránh gọi API liên tục\r\nif (!localStorage.getItem(\'chatbot_token\')) {\r\n    // Lưu ý: Việc lấy username/password từ session phía client khá khó khăn \r\n    // vì lý do bảo mật. Cách này thường dùng khi bạn có một trang trung gian \r\n    // hoặc gọi API lấy token từ Session ID hiện tại.\r\n    \r\n    // Cách thực tế nhất: Gọi một endpoint tùy chỉnh hoặc sử dụng AJAX \r\n    // gửi thông tin đăng nhập từ form login đến login/token.php\r\n    \r\n    const loginForm = document.getElementById(\'login\');\r\n    if (loginForm) {\r\n        loginForm.addEventListener(\'submit\', function() {\r\n            const username = document.getElementById(\'username\').value;\r\n            const password = document.getElementById(\'password\').value;\r\n            const service = \'chatbot\'; // Tên tắt bạn đã sửa trong DB\r\n\r\n            fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n                .then(response => response.json())\r\n                .then(data => {\r\n                    if (data.token) {\r\n                        localStorage.setItem(\'chatbot_token\', data.token);\r\n                        console.log(\'Chatbot Token saved!\');\r\n                    }\r\n                })\r\n                .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n        });\r\n    }\r\n}\r\n</script>', ''),
(1824, 2, 1778728940, NULL, 'additionalhtmlfooter', '<script>\r\nif (!localStorage.getItem(\'chatbot_token\')) {\r\n    const loginForm = document.getElementById(\'login\');\r\n    if (loginForm) {\r\n        loginForm.addEventListener(\'submit\', function() {\r\n            const username = document.getElementById(\'username\').value;\r\n            const password = document.getElementById(\'password\').value;\r\n            const service = \'chatbot\'; // Tên tắt bạn đã sửa trong DB\r\n\r\n            fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n                .then(response => response.json())\r\n                .then(data => {\r\n                    if (data.token) {\r\n                        localStorage.setItem(\'chatbot_token\', data.token);\r\n                        console.log(\'Chatbot Token saved!\');\r\n                    }\r\n                })\r\n                .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n        });\r\n    }\r\n}\r\n</script>', '<script>\r\n// Kiểm tra xem đã có token trong localStorage chưa để tránh gọi API liên tục\r\nif (!localStorage.getItem(\'chatbot_token\')) {\r\n    // Lưu ý: Việc lấy username/password từ session phía client khá khó khăn \r\n    // vì lý do bảo mật. Cách này thường dùng khi bạn có một trang trung gian \r\n    // hoặc gọi API lấy token từ Session ID hiện tại.\r\n    \r\n    // Cách thực tế nhất: Gọi một endpoint tùy chỉnh hoặc sử dụng AJAX \r\n    // gửi thông tin đăng nhập từ form login đến login/token.php\r\n    \r\n    const loginForm = document.getElementById(\'login\');\r\n    if (loginForm) {\r\n        loginForm.addEventListener(\'submit\', function() {\r\n            const username = document.getElementById(\'username\').value;\r\n            const password = document.getElementById(\'password\').value;\r\n            const service = \'chatbot\'; // Tên tắt bạn đã sửa trong DB\r\n\r\n            fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n                .then(response => response.json())\r\n                .then(data => {\r\n                    if (data.token) {\r\n                        localStorage.setItem(\'chatbot_token\', data.token);\r\n                        console.log(\'Chatbot Token saved!\');\r\n                    }\r\n                })\r\n                .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n        });\r\n    }\r\n}\r\n</script>'),
(1825, 2, 1778729540, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Tìm form có chứa trường username và password\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField) {\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\'; // Phải khớp với shortname trong DB của bạn\r\n\r\n        // Gọi API lấy token\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    localStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Token đã được lưu!\');\r\n                }\r\n            })\r\n            .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n    }\r\n});\r\n</script>', '<script>\r\nif (!localStorage.getItem(\'chatbot_token\')) {\r\n    const loginForm = document.getElementById(\'login\');\r\n    if (loginForm) {\r\n        loginForm.addEventListener(\'submit\', function() {\r\n            const username = document.getElementById(\'username\').value;\r\n            const password = document.getElementById(\'password\').value;\r\n            const service = \'chatbot\'; // Tên tắt bạn đã sửa trong DB\r\n\r\n            fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n                .then(response => response.json())\r\n                .then(data => {\r\n                    if (data.token) {\r\n                        localStorage.setItem(\'chatbot_token\', data.token);\r\n                        console.log(\'Chatbot Token saved!\');\r\n                    }\r\n                })\r\n                .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n        });\r\n    }\r\n}\r\n</script>'),
(1826, 2, 1778742646, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Kiểm tra xem có phải form đăng nhập không\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField && !localStorage.getItem(\'chatbot_token\')) {\r\n        // Tạm dừng việc gửi form\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token cho chatbot...\');\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    localStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã lưu Token thành công!\');\r\n                }\r\n                // Sau khi lấy xong (hoặc lỗi), tiếp tục gửi form để đăng nhập vào Moodle\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi lấy token:\', err);\r\n                loginForm.submit(); // Vẫn cho đăng nhập nếu lỗi API\r\n            });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Tìm form có chứa trường username và password\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField) {\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\'; // Phải khớp với shortname trong DB của bạn\r\n\r\n        // Gọi API lấy token\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    localStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Token đã được lưu!\');\r\n                }\r\n            })\r\n            .catch(err => console.error(\'Lỗi lấy token:\', err));\r\n    }\r\n});\r\n</script>'),
(1827, 2, 1778743049, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Kiểm tra xem có phải form đăng nhập không\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField && !sessionStorage.getItem(\'chatbot_token\')) {\r\n        // Tạm dừng việc gửi form\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token cho chatbot...\');\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã lưu Token thành công!\');\r\n                }\r\n                // Sau khi lấy xong (hoặc lỗi), tiếp tục gửi form để đăng nhập vào Moodle\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi lấy token:\', err);\r\n                loginForm.submit(); // Vẫn cho đăng nhập nếu lỗi API\r\n            });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Kiểm tra xem có phải form đăng nhập không\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField && !localStorage.getItem(\'chatbot_token\')) {\r\n        // Tạm dừng việc gửi form\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token cho chatbot...\');\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    localStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã lưu Token thành công!\');\r\n                }\r\n                // Sau khi lấy xong (hoặc lỗi), tiếp tục gửi form để đăng nhập vào Moodle\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi lấy token:\', err);\r\n                loginForm.submit(); // Vẫn cho đăng nhập nếu lỗi API\r\n            });\r\n    }\r\n});\r\n</script>'),
(1828, 2, 1778744017, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n        // LUÔN LUÔN chặn gửi form để lấy Token mới, không quan trọng trong session đã có hay chưa\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã cập nhật Token mới thành công!\');\r\n                } else {\r\n                    sessionStorage.removeItem(\'chatbot_token\');\r\n                }\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi kết nối API Moodle:\', err);\r\n                loginForm.submit(); \r\n            });\r\n    }\r\n});\r\n</script> \r\n\r\n<script>\r\nif (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n    sessionStorage.removeItem(\'chatbot_token\');\r\n}\r\n</script>', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    // Kiểm tra xem có phải form đăng nhập không\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n    \r\n    if (userField && passField && !sessionStorage.getItem(\'chatbot_token\')) {\r\n        // Tạm dừng việc gửi form\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token cho chatbot...\');\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã lưu Token thành công!\');\r\n                }\r\n                // Sau khi lấy xong (hoặc lỗi), tiếp tục gửi form để đăng nhập vào Moodle\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi lấy token:\', err);\r\n                loginForm.submit(); // Vẫn cho đăng nhập nếu lỗi API\r\n            });\r\n    }\r\n});\r\n</script>');
INSERT INTO `mdl_config_log` (`id`, `userid`, `timemodified`, `plugin`, `name`, `value`, `oldvalue`) VALUES
(1829, 2, 1778746458, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n    // 1. XỬ LÝ NÚT MỞ CHATBOT (Chạy ở các trang có nút bấm)\r\n    const chatBtn = document.getElementById(\'open-chatbot-btn\');\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n    \r\n    if (chatBtn && token) {\r\n        // Thay thế placeholder bằng token thật từ sessionStorage\r\n        chatBtn.href = chatBtn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n        console.log(\'Chatbot URL updated with current token.\');\r\n    }\r\n\r\n    // 2. XỬ LÝ LOGOUT (Xóa token khi người dùng thoát)\r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n// 3. XỬ LÝ LOGIN (Chỉ chạy khi người dùng nhấn nút Đăng nhập)\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n        // Chặn gửi form tạm thời để lấy Token\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã cập nhật Token mới thành công!\');\r\n                } else {\r\n                    sessionStorage.removeItem(\'chatbot_token\');\r\n                }\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi kết nối API Moodle:\', err);\r\n                loginForm.submit(); \r\n            });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n        // LUÔN LUÔN chặn gửi form để lấy Token mới, không quan trọng trong session đã có hay chưa\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã cập nhật Token mới thành công!\');\r\n                } else {\r\n                    sessionStorage.removeItem(\'chatbot_token\');\r\n                }\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi kết nối API Moodle:\', err);\r\n                loginForm.submit(); \r\n            });\r\n    }\r\n});\r\n</script> \r\n\r\n<script>\r\nif (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n    sessionStorage.removeItem(\'chatbot_token\');\r\n}\r\n</script>'),
(1830, 2, 1780232765, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-btn\',\r\n        \'open-chatbot-analysis-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n    // 1. XỬ LÝ NÚT MỞ CHATBOT (Chạy ở các trang có nút bấm)\r\n    const chatBtn = document.getElementById(\'open-chatbot-btn\');\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n    \r\n    if (chatBtn && token) {\r\n        // Thay thế placeholder bằng token thật từ sessionStorage\r\n        chatBtn.href = chatBtn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n        console.log(\'Chatbot URL updated with current token.\');\r\n    }\r\n\r\n    // 2. XỬ LÝ LOGOUT (Xóa token khi người dùng thoát)\r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n// 3. XỬ LÝ LOGIN (Chỉ chạy khi người dùng nhấn nút Đăng nhập)\r\ndocument.addEventListener(\'submit\', function(e) {\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n        // Chặn gửi form tạm thời để lấy Token\r\n        e.preventDefault();\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(`http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`)\r\n            .then(response => response.json())\r\n            .then(data => {\r\n                if (data.token) {\r\n                    sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                    console.log(\'Đã cập nhật Token mới thành công!\');\r\n                } else {\r\n                    sessionStorage.removeItem(\'chatbot_token\');\r\n                }\r\n                loginForm.submit();\r\n            })\r\n            .catch(err => {\r\n                console.error(\'Lỗi kết nối API Moodle:\', err);\r\n                loginForm.submit(); \r\n            });\r\n    }\r\n});\r\n</script>'),
(1831, 2, 1780278938, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n\r\n    // XỬ LÝ CÁC NÚT CHATBOT\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-btn\',\r\n        \'open-chatbot-analysis-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    // XỬ LÝ LOGOUT \r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n\r\n// XỬ LÝ LOGIN \r\ndocument.addEventListener(\'submit\', function(e) {\r\n\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n\r\n        e.preventDefault();\r\n\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(\r\n            `http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`\r\n        )\r\n        .then(response => response.json())\r\n        .then(data => {\r\n\r\n            if (data.token) {\r\n                sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                console.log(\'Đã cập nhật Token mới thành công!\');\r\n            } else {\r\n                sessionStorage.removeItem(\'chatbot_token\');\r\n            }\r\n\r\n            loginForm.submit();\r\n        })\r\n        .catch(err => {\r\n            console.error(\'Lỗi kết nối API Moodle:\', err);\r\n            loginForm.submit();\r\n        });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-btn\',\r\n        \'open-chatbot-analysis-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n</script>'),
(1832, 2, 1780907790, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n\r\n    // XỬ LÝ CÁC NÚT CHATBOT\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-suggest-btn\',\r\n        \'open-chatbot-analysis-btn\',\r\n        \'open-chatbot-grading-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    // XỬ LÝ LOGOUT \r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n\r\n// XỬ LÝ LOGIN \r\ndocument.addEventListener(\'submit\', function(e) {\r\n\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n\r\n        e.preventDefault();\r\n\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(\r\n            `http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`\r\n        )\r\n        .then(response => response.json())\r\n        .then(data => {\r\n\r\n            if (data.token) {\r\n                sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                console.log(\'Đã cập nhật Token mới thành công!\');\r\n            } else {\r\n                sessionStorage.removeItem(\'chatbot_token\');\r\n            }\r\n\r\n            loginForm.submit();\r\n        })\r\n        .catch(err => {\r\n            console.error(\'Lỗi kết nối API Moodle:\', err);\r\n            loginForm.submit();\r\n        });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n\r\n    // XỬ LÝ CÁC NÚT CHATBOT\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-btn\',\r\n        \'open-chatbot-analysis-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    // XỬ LÝ LOGOUT \r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n\r\n// XỬ LÝ LOGIN \r\ndocument.addEventListener(\'submit\', function(e) {\r\n\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n\r\n        e.preventDefault();\r\n\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(\r\n            `http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`\r\n        )\r\n        .then(response => response.json())\r\n        .then(data => {\r\n\r\n            if (data.token) {\r\n                sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                console.log(\'Đã cập nhật Token mới thành công!\');\r\n            } else {\r\n                sessionStorage.removeItem(\'chatbot_token\');\r\n            }\r\n\r\n            loginForm.submit();\r\n        })\r\n        .catch(err => {\r\n            console.error(\'Lỗi kết nối API Moodle:\', err);\r\n            loginForm.submit();\r\n        });\r\n    }\r\n});\r\n</script>'),
(1833, 2, 1782378481, NULL, 'additionalhtmlfooter', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n\r\n    // XỬ LÝ CÁC NÚT CHATBOT\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-suggest-btn\',\r\n        \'open-chatbot-analysis-btn\',\r\n        \'open-chatbot-grading-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    // XỬ LÝ LOGOUT \r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n\r\n// XỬ LÝ LOGIN \r\ndocument.addEventListener(\'submit\', function(e) {\r\n\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n\r\n        e.preventDefault();\r\n\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(\r\n            `http://moodle.local/moodle/login/token.php?username=${username}&password=${password}&service=${service}`\r\n        )\r\n        .then(response => response.json())\r\n        .then(data => {\r\n\r\n            if (data.token) {\r\n                sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                console.log(\'Đã cập nhật Token mới thành công!\');\r\n            } else {\r\n                sessionStorage.removeItem(\'chatbot_token\');\r\n            }\r\n\r\n            loginForm.submit();\r\n        })\r\n        .catch(err => {\r\n            console.error(\'Lỗi kết nối API Moodle:\', err);\r\n            loginForm.submit();\r\n        });\r\n    }\r\n});\r\n</script>', '<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', function() {\r\n\r\n    // XỬ LÝ CÁC NÚT CHATBOT\r\n    const token = sessionStorage.getItem(\'chatbot_token\');\r\n\r\n    const buttonIds = [\r\n        \'open-chatbot-suggest-btn\',\r\n        \'open-chatbot-analysis-btn\',\r\n        \'open-chatbot-grading-btn\'\r\n    ];\r\n\r\n    if (token) {\r\n        buttonIds.forEach(function(id) {\r\n            const btn = document.getElementById(id);\r\n\r\n            if (btn) {\r\n                btn.href = btn.href.replace(\'TOKEN_PLACEHOLDER\', token);\r\n                console.log(id + \' URL updated with current token.\');\r\n            }\r\n        });\r\n    }\r\n\r\n    // XỬ LÝ LOGOUT \r\n    if (window.location.href.indexOf(\'login/logout.php\') !== -1) {\r\n        sessionStorage.removeItem(\'chatbot_token\');\r\n        console.log(\'Chatbot token removed due to logout.\');\r\n    }\r\n});\r\n\r\n\r\n// XỬ LÝ LOGIN \r\ndocument.addEventListener(\'submit\', function(e) {\r\n\r\n    const userField = document.querySelector(\'input[name=\"username\"]\');\r\n    const passField = document.querySelector(\'input[name=\"password\"]\');\r\n\r\n    if (userField && passField) {\r\n\r\n        e.preventDefault();\r\n\r\n        const loginForm = e.target;\r\n        const username = userField.value;\r\n        const password = passField.value;\r\n        const service = \'chatbot\';\r\n\r\n        console.log(\'Đang lấy Token mới cho tài khoản:\', username);\r\n\r\n        fetch(\r\n            `http://localhost/moodle/login/token.php?username=${username}&password=${password}&service=${service}`\r\n        )\r\n        .then(response => response.json())\r\n        .then(data => {\r\n\r\n            if (data.token) {\r\n                sessionStorage.setItem(\'chatbot_token\', data.token);\r\n                console.log(\'Đã cập nhật Token mới thành công!\');\r\n            } else {\r\n                sessionStorage.removeItem(\'chatbot_token\');\r\n            }\r\n\r\n            loginForm.submit();\r\n        })\r\n        .catch(err => {\r\n            console.error(\'Lỗi kết nối API Moodle:\', err);\r\n            loginForm.submit();\r\n        });\r\n    }\r\n});\r\n</script>');
