(1, 0, 1, 'Trợ lý ảo hỗ trợ giải bài tập lập trình - CNTT', 'ProgAI-LMS', '', '<p>Hệ thống học tập trực tuyến tích hợp <strong>Chatbot </strong>thông minh, hỗ trợ sinh viên ngành CNTT trong việc <strong>giải quyết các bài tập lập trình</strong>, phân tích và <strong>gợi ý hướng khắc phục lỗi sai</strong> trong mã nguồn một cách tự động.</p>', 0, 'site', 1, 3, 0, 0, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1774580841, 1774587643, 0, 0, 0, 1781402610, NULL, 0, NULL, NULL),
