INSERT INTO `mdl_event` (`id`, `name`, `description`, `format`, `categoryid`, `courseid`, `groupid`, `userid`, `repeatid`, `component`, `modulename`, `instance`, `type`, `eventtype`, `timestart`, `timeduration`, `timesort`, `visible`, `uuid`, `sequence`, `timemodified`, `subscriptionid`, `priority`, `location`) VALUES
(1, 'Bài tập nộp code tới hạn', '<p>Viết các chương trình bằng ngôn ngữ Python</p>\r\n<p>1/ Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 0, 2, 0, 0, 0, NULL, 'assign', 1, 1, 'due', 1774803600, 0, 1774803600, 1, '', 1, 1779266012, NULL, NULL, NULL),
(2, 'Bài tập nộp code tới hạn chấm bài', '<p>Viết các chương trình bằng ngôn ngữ Python</p>\r\n<p>1/ Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 0, 2, 0, 0, 0, NULL, 'assign', 1, 1, 'gradingdue', 1775926800, 0, 1775926800, 1, '', 1, 1779266012, NULL, NULL, NULL),
(3, 'Thống kế và phân tích dữ liệu từ bộ dữ liệu Iris tới hạn', '<p>1/ Viết chương trình Python sử dụng thư viện pandas và matplotlib để đọc bộ dữ liệu Iris, sau đó:</p>\r\n<p>- Hiển thị 5 dòng đầu tiên của dữ liệu.</p>\r\n<p>- Vẽ biểu đồ scatter giữa sepal_length và petal_length, phân biệt màu theo từng loài hoa (species).</p>\r\n<p>2/ Viết chương trình Python dùng thư viện scikit-learn để:</p>\r\n<p>- Chia bộ dữ liệu Iris thành tập huấn luyện và tập kiểm tra.</p>\r\n<p>- Huấn luyện mô hình KNeighborsClassifier.</p>', 1, 0, 2, 0, 2, 0, NULL, 'assign', 2, 1, 'due', 1778950800, 0, 1778950800, 1, '', 1, 1778402053, NULL, NULL, NULL),
(4, 'Thống kế và phân tích dữ liệu từ bộ dữ liệu Iris tới hạn chấm bài', '<p>1/ Viết chương trình Python sử dụng thư viện pandas và matplotlib để đọc bộ dữ liệu Iris, sau đó:</p>\r\n<p>- Hiển thị 5 dòng đầu tiên của dữ liệu.</p>\r\n<p>- Vẽ biểu đồ scatter giữa sepal_length và petal_length, phân biệt màu theo từng loài hoa (species).</p>\r\n<p>2/ Viết chương trình Python dùng thư viện scikit-learn để:</p>\r\n<p>- Chia bộ dữ liệu Iris thành tập huấn luyện và tập kiểm tra.</p>\r\n<p>- Huấn luyện mô hình KNeighborsClassifier.</p>', 1, 0, 2, 0, 2, 0, NULL, 'assign', 2, 1, 'gradingdue', 1779555600, 0, 1779555600, 1, '', 1, 1778402053, NULL, NULL, NULL),
(5, 'Viết chương trình đơn giản tới hạn', '<p>1/  Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/ Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 3, 1, 'due', 1811350800, 0, 1811350800, 1, '', 1, 1780810812, NULL, NULL, NULL),
(6, 'Viết chương trình đơn giản tới hạn chấm bài', '<p>1/  Viết chương trình tính số Fibonanci đến n (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>\r\n<p>2/ Viết chương trình in ra tam giác pascal có n tầng (n là số nguyên &gt;0 và n được nhập từ bàn phím)</p>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 3, 1, 'gradingdue', 1811955600, 0, 1811955600, 1, '', 1, 1780810812, NULL, NULL, NULL),
(7, 'Viết chương trình áp dụng hướng đối tượng tới hạn', '<p>Một đơn vị sản xuất gồm có các cán bộ là công nhân, kỹ sư, nhân viên. Mỗi cán bộ cần quản lý các dữ liệu: Họ tên, tuổi, giới tính(nam, nữ, khác), địa chỉ.</p>\r\n<ul>\r\n<li>Cấp công nhân sẽ có thêm các thuộc tính riêng: Bậc (1 đến 10).</li>\r\n<li>Cấp kỹ sư có thuộc tính riêng: Nghành đào tạo.</li>\r\n<li>Các nhân viên có thuộc tính riêng: Công việc.</li>\r\n</ul>\r\n<p>Yêu cầu 1: Xây dựng các lớp <em>CongNhan</em>, <em>KySu</em>, <em>NhanVien</em> kế thừa từ lớp <em>CanBo</em>.</p>\r\n<p>Yêu cầu 2: Xây dựng lớp <em>QLCB</em>(quản lý cán bộ) cài đặt các phương thức thực hiện các chức năng sau:</p>\r\n<ul>\r\n<li>Nhập thông tin cho 1 cán bộ để thêm vào danh sách.</li>\r\n<li>Hiển thị danh sách họ tên các cán bộ. </li>\r\n</ul>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 4, 1, 'due', 1811350800, 0, 1811350800, 1, '', 1, 1782459693, NULL, NULL, NULL),
(8, 'Viết chương trình áp dụng hướng đối tượng tới hạn chấm bài', '<p>Một đơn vị sản xuất gồm có các cán bộ là công nhân, kỹ sư, nhân viên. Mỗi cán bộ cần quản lý các dữ liệu: Họ tên, tuổi, giới tính(nam, nữ, khác), địa chỉ.</p>\r\n<ul>\r\n<li>Cấp công nhân sẽ có thêm các thuộc tính riêng: Bậc (1 đến 10).</li>\r\n<li>Cấp kỹ sư có thuộc tính riêng: Nghành đào tạo.</li>\r\n<li>Các nhân viên có thuộc tính riêng: Công việc.</li>\r\n</ul>\r\n<p>Yêu cầu 1: Xây dựng các lớp <em>CongNhan</em>, <em>KySu</em>, <em>NhanVien</em> kế thừa từ lớp <em>CanBo</em>.</p>\r\n<p>Yêu cầu 2: Xây dựng lớp <em>QLCB</em>(quản lý cán bộ) cài đặt các phương thức thực hiện các chức năng sau:</p>\r\n<ul>\r\n<li>Nhập thông tin cho 1 cán bộ để thêm vào danh sách.</li>\r\n<li>Hiển thị danh sách họ tên các cán bộ. </li>\r\n</ul>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 4, 1, 'gradingdue', 1811955600, 0, 1811955600, 1, '', 1, 1782459693, NULL, NULL, NULL),
(9, 'Viết chương trình áp dụng hướng đối tượng 2 tới hạn', '<p>Sinh viên đọc các file bên dưới:</p>\r\n<ul>\r\n<li>Thực hiện theo yêu cầu: file De_bai.docx</li>\r\n<li>Tiêu chi chấm điểm: Tieu_chi_cham_diem.docx</li>\r\n</ul>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 5, 1, 'due', 1781197200, 0, 1781197200, 1, '', 1, 1780635656, NULL, NULL, NULL),
(10, 'Viết chương trình áp dụng hướng đối tượng 2 tới hạn chấm bài', '<p>Sinh viên đọc các file bên dưới:</p>\r\n<ul>\r\n<li>Thực hiện theo yêu cầu: file De_bai.docx</li>\r\n<li>Tiêu chi chấm điểm: Tieu_chi_cham_diem.docx</li>\r\n</ul>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 5, 1, 'gradingdue', 1781802000, 0, 1781802000, 1, '', 1, 1780635656, NULL, NULL, NULL),
(11, 'Tương tác cơ sở dữ liệu tới hạn', '<p style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>Cho cơ sở dữ liệu <strong>todo_db</strong> </span><span lang=\"en-us\" xml:lang=\"en-us\">với</span><span> bảng <strong>tasks</strong> gồm các trường:</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>id (INT, khóa chính, tự tăng)</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>task_name (</span><span lang=\"en-us\" xml:lang=\"en-us\">N</span><span>VARCHAR)</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>created_at (TIMESTAMP)</span></p>\r\n<p style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>Hãy xây dựng một ứng dụng <strong>To-Do List</strong> bằng <strong>PHP</strong> sử dụng <strong>PDO</strong> để thực hiện các chức năng sau:</span></p>\r\n<h6 style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>1. Kết nối cơ sở dữ liệu</span></h6>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Kết nối đến cơ sở dữ liệu todo_db </span><span>bằng PDO.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Sử dụng try-catch</span><span> để xử lý lỗi kết nối.</span></p>\r\n<h6 style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>2. Hiển thị danh sách công việc</span></h6>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Lấy toàn bộ công việc từ bảng tasks </span><span>, sắp xếp công việc mới nhất lên đầu.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Hiển thị danh sách trên giao diện.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Nếu chưa có dữ liệu, hiển thị thông báo: <strong>\"Chưa có công việc nào cần làm!\"</strong></span></p>\r\n<h6 style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>3. Thêm công việc</span></h6>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Tạo form nhập tên công việc.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Khi gửi form:</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 72pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:\'Courier New\';\"><span>o<span style=\"font:7pt \'Times New Roman\';\">   </span></span></span><span>Kiểm tra dữ liệu không được rỗng.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 72pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:\'Courier New\';\"><span>o<span style=\"font:7pt \'Times New Roman\';\">   </span></span></span><span>Sử dụng Prepared Statement để thêm dữ liệu vào bảng tasks </span><span>.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 72pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:\'Courier New\';\"><span>o<span style=\"font:7pt \'Times New Roman\';\">   </span></span></span><span>Sau khi thêm thành công, chuyển hướng về trang chính để tránh gửi lại dữ liệu khi làm mới trang.</span></p>\r\n<h6 style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>4. Xóa công việc</span></h6>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Hiển thị nút hoặc liên kết <strong>Xóa</strong> bên cạnh mỗi công việc.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Truyền</span><span> id công việc cần xóa qua URL.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Sử dụng Prepared Statement để xóa dữ liệu tương ứng.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Sau khi xóa thành công, tải lại trang để cập nhật danh sách.</span></p>\r\n<h6 style=\"margin:0cm;margin-bottom:0.0001pt;line-height:150%;\"><span>Yêu cầu kỹ thuật</span></h6>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Sử dụng PHP và thư viện PDO.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Áp dụng Prepared Statement cho các thao tác với cơ sở dữ liệu.</span></p>\r\n<p style=\"text-indent:-18pt;line-height:150%;margin:0cm 0cm 0.0001pt 36pt;\"><span style=\"font-size:10pt;line-height:150%;font-family:Symbol;\"><span>·<span style=\"font:7pt \'Times New Roman\';\">        </span></span></span><span>Ứng dụng phải hoạt động trên môi trường Localhost.</span></p>', 1, 0, 4, 0, 0, 0, NULL, 'assign', 6, 1, 'due', 1812992400, 0, 1812992400, 1, '', 1, 1782459777, NULL, NULL, NULL),
