/moodle\\/login\\/token.php?username=${username}&password=${password}&service=${service}`)\\r\\n            .then(response => response.json())\\r\\n            .then(data => {\\r\\n                if (data.token) {\\r\\n                    localStorage.setItem(\'chatbot_token\', data.token);\\r\\n                    console.log(\'Token \\u0111\\u00e3 \\u0111\\u01b0\\u1ee3c l\\u01b0u!\');\\r\\n                }\\r\\n            })\\r\\n            .catch(err => console.error(\'L\\u1ed7i l\\u1ea5y token:\', err));\\r\\n    }\\r\\n});\\r\\n<\\/script>\",\"plugin\":null}', 1778729540, 'web', '0:0:0:0:0:0:0:1', NULL),
