INSERT INTO `mdl_notifications` (`id`, `useridfrom`, `useridto`, `subject`, `fullmessage`, `fullmessageformat`, `fullmessagehtml`, `smallmessage`, `component`, `eventtype`, `contexturl`, `contexturlname`, `timeread`, `timecreated`, `customdata`) VALUES
(1, 2, 3, 'Chào mừng bạn đến với Lập trình Python Cơ bản', 'Dear test 01 student, you are enrolled in the course Lập trình Python Cơ bản.', 4, 'Dear test 01 student, you are enrolled in the course Lập trình Python Cơ bản.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://localhost/moodle/user/view.php?id=3&amp;course=2', 'Lập trình Python Cơ bản', NULL, 1774767308, NULL),
(2, -10, 3, 'Bạn đã nộp bài làm cho Bài tập nộp code.', 'PY01 -> Bài tập -> Bài tập nộp code\n---------------------------------------------------------------------\nBạn đã nộp bài làm cho \'Bài tập nộp code\' .\n\nBạn có thể thấy trạng thái của bài làm:\n\n      http://localhost/moodle/mod/assign/view.php?id=2\n\n---------------------------------------------------------------------\n', 2, '<p><font face=\"sans-serif\"><a href=\"http://localhost/moodle/course/view.php?id=2\">PY01</a> -><a href=\"http://localhost/moodle/mod/assign/index.php?id=2\">Bài tập</a> -><a href=\"http://localhost/moodle/mod/assign/view.php?id=2\">Bài tập nộp code</a></font></p><hr /><font face=\"sans-serif\"><p><p>Bạn đã nộp bài làm cho \'<i>Bài tập nộp code</i>\'.</p>\n<p>Bạn có thể thấy trạng thái của bài làm <a href=\"http://localhost/moodle/mod/assign/view.php?id=2\"></a>.</p></p></font><hr />', 'Bạn đã nộp bài làm cho Bài tập nộp code.', 'mod_assign', 'assign_notification', 'http://localhost/moodle/mod/assign/view.php?id=2', 'Bài tập nộp code', NULL, 1774767738, '{\"cmid\":\"2\",\"instance\":\"1\",\"messagetype\":\"submissionreceipt\",\"blindmarking\":false,\"uniqueidforuser\":\"1\",\"courseid\":\"2\"}'),
(3, 2, 4, 'Chào mừng bạn đến với Lập trình Python Cơ bản', 'Dear test 02 student, you are enrolled in the course Lập trình Python Cơ bản.', 4, 'Dear test 02 student, you are enrolled in the course Lập trình Python Cơ bản.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://localhost/moodle/user/view.php?id=4&amp;course=2', 'Lập trình Python Cơ bản', NULL, 1774768052, NULL),
